USE ktp_database;
CREATE TABLE ktp_data (id INT PRIMARY KEY AUTO_INCREMENT, nik VARCHAR(16) UNIQUE NOT NULL, nama VARCHAR(255) NOT NULL, alamat TEXT, tanggal_lahir DATE, telp VARCHAR(20), email VARCHAR(255), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE query_audit_log (id INT PRIMARY KEY AUTO_INCREMENT, timestamp DATETIME DEFAULT CURRENT_TIMESTAMP, source_ip VARCHAR(45), query TEXT, risk_level ENUM('LOW', 'MEDIUM', 'HIGH', 'CRITICAL'), action_taken VARCHAR(255), forensic_json JSON);
CREATE INDEX idx_timestamp ON query_audit_log(timestamp);
CREATE INDEX idx_source_ip ON query_audit_log(source_ip);
